import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'sonner';
import { Mail, Lock, Eye, EyeOff } from 'lucide-react';

const Login = () => {
  const navigate = useNavigate();
  const { login } = useAuth();
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [formData, setFormData] = useState({
    email: '',
    password: '',
  });

  const handleSubmit = (e) => {
    e.preventDefault();
    const result = login(formData.email, formData.password);

    if (result.success) {
      toast.success('Login berhasil!');
      setTimeout(() => {
        navigate('/');
      }, 1000);
    } else {
      toast.error(result.message);
    }
  };

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  return (
    <div
      className="min-h-screen flex font-secondary"
      style={{ backgroundColor: '#0a0a0a' }}
      data-testid="login-page"
    >
      {/* Left: Truck Image */}
      <div className="hidden lg:flex w-[60%] relative overflow-hidden rounded-r-3xl">
        <img
          src="/images/truck-bg.jpg"
          alt="Mandiri Perkasa Logistics"
          className="w-full h-full object-cover"
        />
        {/* Logo overlay */}
        <div className="absolute top-6 left-6 flex items-center gap-3">
          <img src="/logo-mpl.jpg" alt="MPL Logo" className="h-10 w-auto" />
          <span className="text-white font-bold text-xl tracking-widest uppercase font-primary">
            Mandiri Perkasa
          </span>
        </div>
      </div>

      {/* Right: Form Panel */}
      <div className="flex-1 flex flex-col justify-center px-10 lg:px-16 xl:px-24">
        {/* Mobile logo */}
        <div className="flex lg:hidden items-center gap-3 mb-10">
          <img src="/logo-mpl.jpg" alt="MPL Logo" className="h-8 w-auto" />
          <span className="text-white font-bold text-lg tracking-widest uppercase font-primary">
            Mandiri Perkasa
          </span>
        </div>

        <div className="max-w-sm w-full mx-auto lg:mx-0">
          {/* Title */}
          <h2
            className="text-4xl font-bold mb-3 font-primary text-primary"
            data-testid="login-title"
          >
            Masuk
          </h2>
          <p className="text-gray-400 text-sm mb-8">
            Jika kamu belum punya akun kamu dapat{' '}
            <Link
              to="/daftar"
              className="font-semibold transition-colors text-primary hover:text-primary"
              data-testid="register-link"
            >
              Daftar disini
            </Link>
          </p>

          {/* Form */}
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Email */}
            <div>
              <label
                htmlFor="email"
                className="block text-sm font-medium text-gray-300 mb-2"
              >
                Email
              </label>
              <div className="relative flex items-center">
                <Mail
                  className="absolute left-0 h-5 w-5 text-primary"
                />
                <input
                  id="email"
                  name="email"
                  type="email"
                  required
                  value={formData.email}
                  onChange={handleChange}
                  className="w-full pl-8 pr-3 py-2 bg-transparent text-white text-sm placeholder-gray-500 border-b border-gray-600 focus:outline-none focus:border-primary transition-colors"
                  placeholder="Masukan Email Anda"
                  data-testid="login-email"
                />
              </div>
            </div>

            {/* Password */}
            <div>
              <label
                htmlFor="password"
                className="block text-sm font-medium text-gray-300 mb-2"
              >
                Kata Sandi
              </label>
              <div className="relative flex items-center">
                <Lock
                  className="absolute left-0 h-5 w-5 text-primary"
                />
                <input
                  id="password"
                  name="password"
                  type={showPassword ? 'text' : 'password'}
                  required
                  value={formData.password}
                  onChange={handleChange}
                  className="w-full pl-8 pr-10 py-2 bg-transparent text-white text-sm placeholder-gray-500 border-b border-gray-600 focus:outline-none focus:border-primary transition-colors"
                  placeholder="Masukan Kata Sandi Anda"
                  data-testid="login-password"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-0 flex items-center text-gray-500 hover:text-gray-300"
                  data-testid="toggle-password"
                >
                  {showPassword ? (
                    <EyeOff className="h-5 w-5" />
                  ) : (
                    <Eye className="h-5 w-5" />
                  )}
                </button>
              </div>
            </div>

            {/* Remember me & Forgot password */}
            <div className="flex items-center justify-between pt-1">
              <label className="flex items-center gap-2 cursor-pointer select-none">
                <input
                  type="checkbox"
                  checked={rememberMe}
                  onChange={(e) => setRememberMe(e.target.checked)}
                  className="w-4 h-4 rounded border border-gray-600 bg-transparent accent-primary cursor-pointer"
                />
                <span className="text-sm text-gray-400">Ingat saya</span>
              </label>
              <Link
                to="/lupa-password"
                className="text-sm text-gray-400 hover:text-primary transition-colors"
              >
                Lupa kata sandi ?
              </Link>
            </div>

            {/* Submit */}
            <div className="pt-2">
              <button
                type="submit"
                className="w-full py-3 rounded-full font-bold text-base text-black bg-primary hover:bg-primary font-primary transition-colors"
                data-testid="login-submit-button"
              >
                Masuk
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;
